#!/usr/bin/env python3
"""Datagate - CSV conversion and dataset serving server."""

import argparse
import chardet
import csv
import hashlib
import io
import json
import os
import re
import sys
import time
from http.server import HTTPServer, BaseHTTPRequestHandler
from typing import Optional
from urllib.parse import urlparse, parse_qs
import urllib.request
import urllib.error


class Config:
    """Configuration management with precedence: defaults < file < env vars."""

    def __init__(self):
        # Built-in defaults
        self._max_source_size: Optional[int] = None
        self._origin_allowlist: Optional[list] = None
        self._require_tls: bool = False
        self._storage_dir: str = "./data"
        self._cache_enabled: bool = True

        # Parse configuration
        self._load_config()

    def _load_config(self):
        """Load configuration from file and/or environment variables."""
        # Load from config file if specified
        config_file = os.environ.get("DATAGATE_CONFIG")
        if config_file:
            self._load_config_file(config_file)

        # Environment variables override config file
        self._load_env_vars()

        # Ensure storage directory exists
        self._ensure_storage_dir()

    def _load_config_file(self, filepath: str):
        """Load configuration from KEY=VALUE file."""
        try:
            with open(filepath, 'r') as f:
                for line in f:
                    line = line.strip()
                    # Skip blank lines and comments
                    if not line or line.startswith('#'):
                        continue

                    if '=' not in line:
                        raise ValueError(f"Invalid config line: {line}")

                    key, value = line.split('=', 1)
                    key = key.strip()
                    value = value.strip()

                    if key == "MAX_SOURCE_SIZE":
                        self._max_source_size = int(value)
                    elif key == "ORIGIN_ALLOWLIST":
                        self._origin_allowlist = [v.strip() for v in value.split(',') if v.strip()]
                    elif key == "REQUIRE_TLS":
                        self._require_tls = self._parse_bool(value)
                    elif key == "STORAGE_DIR":
                        self._storage_dir = value
                    elif key == "CACHE_ENABLED":
                        self._cache_enabled = self._parse_bool(value)
                    else:
                        raise ValueError(f"Unknown config key: {key}")
        except FileNotFoundError:
            raise ValueError(f"Config file not found: {filepath}")
        except ValueError as e:
            raise ValueError(f"Invalid config: {e}")

    def _load_env_vars(self):
        """Load configuration from environment variables."""
        if "MAX_SOURCE_SIZE" in os.environ:
            val = os.environ["MAX_SOURCE_SIZE"].strip()
            if val:
                self._max_source_size = int(val)

        if "ORIGIN_ALLOWLIST" in os.environ:
            val = os.environ["ORIGIN_ALLOWLIST"].strip()
            if val:
                self._origin_allowlist = [v.strip() for v in val.split(',') if v.strip()]

        if "REQUIRE_TLS" in os.environ:
            val = os.environ["REQUIRE_TLS"].strip()
            if val:
                self._require_tls = self._parse_bool(val)

        if "STORAGE_DIR" in os.environ:
            val = os.environ["STORAGE_DIR"].strip()
            if val:
                self._storage_dir = val

        if "CACHE_ENABLED" in os.environ:
            val = os.environ["CACHE_ENABLED"].strip()
            if val:
                self._cache_enabled = self._parse_bool(val)

    def _parse_bool(self, value: str) -> bool:
        """Parse boolean value with strict validation."""
        true_values = {"1", "true", "yes", "on"}
        false_values = {"0", "false", "no", "off"}

        lower_value = value.lower()
        if lower_value in true_values:
            return True
        elif lower_value in false_values:
            return False

        raise ValueError(f"Invalid boolean value: '{value}'")

    def _ensure_storage_dir(self):
        """Create storage directory if it doesn't exist."""
        if self._storage_dir and not os.path.exists(self._storage_dir):
            os.makedirs(self._storage_dir, exist_ok=True)

    @property
    def max_source_size(self) -> Optional[int]:
        return self._max_source_size

    @property
    def origin_allowlist(self) -> Optional[list]:
        return self._origin_allowlist

    @property
    def require_tls(self) -> bool:
        return self._require_tls

    @property
    def storage_dir(self) -> str:
        return self._storage_dir

    @property
    def cache_enabled(self) -> bool:
        return self._cache_enabled


# Global config instance
config: Config | None = None

# Storage for datasets - keyed by deterministic ID
datasets = {}

# Cache control state
_cache_enabled: bool | None = None


def parse_cache_enabled() -> bool:
    """Parse CACHE_ENABLED environment variable with strict case-insensitive validation.

    Valid true values: 1, true, yes, on (case-insensitive)
    Valid false values: 0, false, no, off (case-insensitive)
    Invalid values cause the server to fail on startup.
    """
    value = os.environ.get("CACHE_ENABLED", "true").strip()

    true_values = {"1", "true", "yes", "on"}
    false_values = {"0", "false", "no", "off"}

    lower_value = value.lower()
    if lower_value in true_values:
        return True
    elif lower_value in false_values:
        return False

    print(f"FATAL: Invalid CACHE_ENABLED value: '{value}'", file=sys.stderr)
    print("Valid values: 1, true, yes, on (true) / 0, false, no, off (false)", file=sys.stderr)
    sys.exit(1)


def is_cache_enabled() -> bool:
    """Return whether caching is enabled, parsing on first call."""
    global _cache_enabled
    if _cache_enabled is None:
        _cache_enabled = parse_cache_enabled()
    return _cache_enabled



def generate_dataset_id(source: str) -> str:
    """Generate a deterministic ID from the source."""
    return hashlib.sha256(source.encode('utf-8')).hexdigest()[:16]


def detect_charset(content: bytes) -> str:
    """Detect character encoding from content bytes."""
    result = chardet.detect(content)
    return result['encoding'] or 'utf-8'


def infer_delimiter(sample: str) -> str:
    """Infer the CSV delimiter from a sample string."""
    delimiters = {',': 0, ';': 0, '\t': 0}

    lines = sample.split('\n')
    if len(lines) < 2:
        return ','  # Default to comma if not enough lines

    header_line = lines[0]

    for delim in delimiters:
        # Count occurrences in header
        count = header_line.count(delim)
        if count > delimiters[delim]:
            delimiters[delim] = count

    # Return the delimiter with highest count
    return max(delimiters, key=delimiters.get)


def infer_type(value: str):
    """Infer the type of a CSV value.

    - Integers/decimals become JSON numbers
    - Time-like values (e.g., 08:30, 9:15, 12:00) remain text
    - Strings remain text
    """
    value = value.strip()

    # Check if it's a time-like value (contains colon, HH:MM format)
    if ':' in value:
        # Match time patterns like 08:30, 9:15, 12:00
        time_pattern = r'^\d{1,2}:\d{2}$'
        if re.match(time_pattern, value):
            return value  # Keep time as text

    # Try to parse as integer
    try:
        return int(value)
    except ValueError:
        pass

    # Try to parse as float/decimal
    try:
        return float(value)
    except ValueError:
        pass

    # Return as string
    return value


def parse_csv_content(content: bytes, charset: Optional[str] = None):
    """Parse CSV content bytes into columns and rows."""
    # Determine charset
    if charset:
        try:
            text = content.decode(charset)
        except (UnicodeDecodeError, LookupError) as e:
            raise ValueError(f"Invalid charset: {str(e)}")
    else:
        detected_charset = detect_charset(content)
        try:
            text = content.decode(detected_charset)
        except UnicodeDecodeError as e:
            raise ValueError(f"Failed to decode content: {str(e)}")

    # Check if content looks like CSV
    if '\n' not in text and '\r' not in text:
        raise ValueError("Non-tabular content")

    # Infer delimiter from first few lines
    sample = '\n'.join(text.split('\n')[:5])
    delimiter = infer_delimiter(sample)

    # Parse CSV
    lines = text.strip().split('\n')
    if len(lines) < 2:
        raise ValueError("A valid file requires at least one header row and one data row")

    # Use csv.reader for proper parsing
    reader = csv.reader(lines, delimiter=delimiter)

    rows = list(reader)

    if len(rows) < 2:
        raise ValueError("A valid file requires at least one header row and one data row")

    columns = rows[0]
    data_rows = rows[1:]

    # Validate that it's tabular (all rows have same number of columns or fewer)
    if not all(len(row) <= len(columns) for row in data_rows):
        raise ValueError("Non-tabular content - inconsistent column counts")

    # Pad rows to match column count
    for row in data_rows:
        while len(row) < len(columns):
            row.append('')

    # Infer types for each value
    typed_rows = []
    for row in data_rows[:100]:  # Limit to 100 rows for storage
        typed_row = [infer_type(val) for val in row[:len(columns)]]
        typed_rows.append(typed_row)

    return columns, typed_rows


def parse_excel_content(content: bytes, filename: str):
    """Parse Excel (.xls or .xlsx) content into columns and rows."""
    try:
        if filename.endswith('.xlsx'):
            import openpyxl
            workbook = openpyxl.load_workbook(io.BytesIO(content), read_only=True, data_only=True)
        elif filename.endswith('.xls'):
            import xlrd
            workbook = xlrd.open_workbook(file_contents=content)
        else:
            raise ValueError("Unsupported format")
    except ImportError as e:
        raise ValueError(f"Missing library: {str(e)}")
    except Exception as e:
        raise ValueError(f"Failed to parse Excel file: {str(e)}")

    # Get the first worksheet
    if filename.endswith('.xlsx'):
        sheet = workbook.active
        if sheet is None:
            raise ValueError("No sheets found")

        rows = []
        for row in sheet.iter_rows(values_only=True):
            rows.append(list(row) if row else [])

        if len(rows) < 2:
            raise ValueError("A valid file requires at least one header row and one data row")

        columns = [str(c) if c is not None else '' for c in rows[0]]
        data_rows = rows[1:]

        # Pad rows to match column count
        for row in data_rows:
            while len(row) < len(columns):
                row.append(None)

        # Convert to typed values and limit to 100 rows
        typed_rows = []
        for row in data_rows[:100]:
            typed_row = []
            for val in row[:len(columns)]:
                if val is None:
                    typed_row.append('')
                elif isinstance(val, (int, float)):
                    typed_row.append(val)
                else:
                    typed_row.append(str(val))
            typed_rows.append(typed_row)

        return columns, typed_rows

    elif filename.endswith('.xls'):
        sheet = workbook.sheet_by_index(0)
        if sheet.nrows < 2:
            raise ValueError("A valid file requires at least one header row and one data row")

        columns = [str(sheet.cell_value(0, col)) for col in range(sheet.ncols)]
        data_rows = []

        for row_idx in range(1, min(sheet.nrows, 101)):  # Limit to 100 data rows
            row = []
            for col_idx in range(sheet.ncols):
                val = sheet.cell_value(row_idx, col_idx)
                row.append(val)
            data_rows.append(row)

        # Pad rows to match column count
        for row in data_rows:
            while len(row) < len(columns):
                row.append('')

        # Convert to typed values
        typed_rows = []
        for row in data_rows:
            typed_row = []
            for val in row[:len(columns)]:
                if val == '':
                    typed_row.append('')
                elif isinstance(val, (int, float)):
                    typed_row.append(val)
                else:
                    typed_row.append(str(val))
            typed_rows.append(typed_row)

        return columns, typed_rows

    raise ValueError("Unsupported format")


def fetch_and_parse_csv(source_url: str, charset: Optional[str] = None):
    """Fetch CSV from URL and parse it into columns and rows."""
    try:
        request = urllib.request.Request(
            source_url,
            headers={'User-Agent': 'Datagate/1.0'}
        )
        with urllib.request.urlopen(request, timeout=30) as response:
            content = response.read()
    except urllib.error.URLError as e:
        raise ValueError(f"Source unreachable: {str(e)}")
    except Exception as e:
        raise ValueError(f"Failed to fetch source: {str(e)}")

    return parse_csv_content(content, charset)


class DatagateHandler(BaseHTTPRequestHandler):
    """HTTP request handler for Datagate."""

    def log_message(self, format, *args):
        """Suppress default logging."""
        pass

    def send_cors_headers(self):
        """Add CORS headers to response."""
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'GET, OPTIONS, POST')
        self.send_header('Access-Control-Allow-Headers', '*')

    def send_json_response(self, status_code: int, data: dict):
        """Send a JSON response with CORS headers."""
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.send_cors_headers()
        self.end_headers()
        self.wfile.write(json.dumps(data).encode('utf-8'))

    def do_OPTIONS(self):
        """Handle CORS preflight requests."""
        self.send_response(200)
        self.send_cors_headers()
        self.end_headers()

    def do_GET(self):
        """Handle GET requests."""
        parsed_path = urlparse(self.path)
        path = parsed_path.path
        query_params = parse_qs(parsed_path.query)

        # Debug logging
        sys.stderr.write(f"DEBUG: path={path}, query={parsed_path.query}, params={query_params}\n")

        try:
            if path == '/convert':
                self.handle_convert(query_params)
            elif path.endswith('/export') and '/datasets/' in path:
                # Handle /datasets/<id>/export
                dataset_id = path.split('/')[2]  # datasets/<id>/export
                self.handle_export(dataset_id, query_params)
            elif path.startswith('/datasets/'):
                dataset_id = path.split('/')[-1]
                self.handle_dataset(dataset_id)
            else:
                self.send_json_response(404, {
                    'ok': False,
                    'error': 'Not found'
                })
        except Exception as e:
            self.send_json_response(500, {
                'ok': False,
                'error': str(e)
            })

    def do_POST(self):
        """Handle POST requests."""
        parsed_path = urlparse(self.path)
        path = parsed_path.path

        try:
            if path == '/upload':
                self.handle_upload()
            elif path == '/convert':
                self.handle_convert_post()
            else:
                self.send_json_response(404, {
                    'ok': False,
                    'error': 'Not found'
                })
        except Exception as e:
            self.send_json_response(500, {
                'ok': False,
                'error': str(e)
            })

    def handle_convert(self, query_params: dict):
        """Handle /convert endpoint."""
        # Check required source parameter
        if 'source' not in query_params:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing source parameter'
            })
            return

        source_url = query_params['source'][0]

        # Validate URL
        try:
            parsed_url = urlparse(source_url)
            if not parsed_url.scheme or not parsed_url.netloc:
                raise ValueError("Invalid URL")
        except Exception:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Invalid URL'
            })
            return

        # Get charset if provided
        charset = query_params['charset'][0] if 'charset' in query_params else None

        # Validate charset if provided
        if charset:
            try:
                # Test if charset is valid by trying to encode/decode
                'test'.encode(charset)
            except (LookupError, TypeError):
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Unsupported or malformed charset'
                })
                return

        # Generate deterministic ID
        dataset_id = generate_dataset_id(source_url)

        # Handle force parameter
        force = 'force' in query_params

        # Validate force parameter - presence only, no value allowed
        # parse_qs returns a list of values for each key
        if force:
            force_values = query_params['force']
            # Force with multiple entries (duplicate keys) is invalid
            if len(force_values) > 1:
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Invalid force parameter'
                })
                return
            # Force with any non-empty value is invalid
            if force_values and force_values[0].strip() != '':
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Invalid force parameter'
                })
                return

        # Determine if we should use the cache
        caching_enabled = is_cache_enabled()

        # Check if we already have this dataset and caching is enabled
        has_cached_dataset = dataset_id in datasets

        # Handle force: if caching is enabled and force is present, re-ingest
        if force and caching_enabled:
            # Store existing data before attempting re-ingestion
            existing_dataset = datasets.get(dataset_id)

            # Fetch and parse CSV
            try:
                columns, rows = fetch_and_parse_csv(source_url, charset)
                datasets[dataset_id] = {
                    'columns': columns,
                    'rows': rows
                }
            except ValueError as e:
                error_msg = str(e)
                # Forced re-ingestion failure: keep prior dataset queryable
                if existing_dataset is not None:
                    datasets[dataset_id] = existing_dataset
                if 'unreachable' in error_msg or 'Failed to fetch' in error_msg:
                    self.send_json_response(404, {
                        'ok': False,
                        'error': error_msg
                    })
                else:
                    self.send_json_response(400, {
                        'ok': False,
                        'error': error_msg
                    })
                return

            # Successful re-ingestion
            self.send_json_response(200, {
                'ok': True,
                'endpoint': f'/datasets/{dataset_id}'
            })
            return

        # Regular behavior: use cache if available and enabled
        if has_cached_dataset and caching_enabled:
            # Return cached dataset id without re-downloading
            self.send_json_response(200, {
                'ok': True,
                'endpoint': f'/datasets/{dataset_id}'
            })
            return

        # Either no cached dataset, or caching disabled - fetch fresh data
        try:
            columns, rows = fetch_and_parse_csv(source_url, charset)
            datasets[dataset_id] = {
                'columns': columns,
                'rows': rows
            }
        except ValueError as e:
            error_msg = str(e)
            if 'unreachable' in error_msg or 'Failed to fetch' in error_msg:
                self.send_json_response(404, {
                    'ok': False,
                    'error': error_msg
                })
            else:
                self.send_json_response(400, {
                    'ok': False,
                    'error': error_msg
                })
            return

        self.send_json_response(200, {
            'ok': True,
            'endpoint': f'/datasets/{dataset_id}'
        })

    def handle_convert_post(self):
        """Handle POST /convert for file uploads."""
        # Parse multipart form data
        content_type = self.headers.get('Content-Type', '')

        if not content_type.startswith('multipart/form-data'):
            self.send_json_response(415, {
                'ok': False,
                'error': 'Non-multipart upload'
            })
            return

        # Parse boundary
        if 'boundary=' not in content_type:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Malformed multipart'
            })
            return

        boundary = content_type.split('boundary=')[1].strip()
        if boundary.startswith('"') and boundary.endswith('"'):
            boundary = boundary[1:-1]

        # Read the body
        content_length = int(self.headers.get('Content-Length', 0))
        body = self.rfile.read(content_length)

        # Parse multipart
        parts = self.parse_multipart(body, boundary)

        if 'file' not in parts and 'attachment' not in parts:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing file field'
            })
            return

        # Get the file part (prefer 'file' over 'attachment')
        file_part = parts.get('file') or parts.get('attachment')
        if not file_part:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing file field'
            })
            return

        filename = file_part.get('filename', '')
        content_bytes = file_part.get('content', b'')

        if not filename or not content_bytes:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing file field'
            })
            return

        # Determine format and parse
        charset = None
        try:
            if filename.endswith('.csv'):
                columns, rows = parse_csv_content(content_bytes, charset)
            elif filename.endswith(('.xls', '.xlsx')):
                columns, rows = parse_excel_content(content_bytes, filename)
            else:
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Unsupported format'
                })
                return
        except ValueError as e:
            self.send_json_response(400, {
                'ok': False,
                'error': str(e)
            })
            return

        # Generate deterministic ID based on file content
        dataset_id = generate_dataset_id(content_bytes.decode('utf-8', errors='replace'))

        # Store dataset
        datasets[dataset_id] = {
            'columns': columns,
            'rows': rows
        }

        self.send_json_response(200, {
            'ok': True,
            'endpoint': f'/datasets/{dataset_id}'
        })

    def handle_upload(self):
        """Handle POST /upload endpoint."""
        # Parse multipart form data
        content_type = self.headers.get('Content-Type', '')

        if not content_type.startswith('multipart/form-data'):
            self.send_json_response(415, {
                'ok': False,
                'error': 'Non-multipart upload'
            })
            return

        # Parse boundary
        if 'boundary=' not in content_type:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Malformed multipart'
            })
            return

        boundary = content_type.split('boundary=')[1].strip()
        if boundary.startswith('"') and boundary.endswith('"'):
            boundary = boundary[1:-1]

        # Read the body
        content_length = int(self.headers.get('Content-Length', 0))
        body = self.rfile.read(content_length)

        # Parse multipart
        parts = self.parse_multipart(body, boundary)

        if 'file' not in parts and 'attachment' not in parts:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing file field'
            })
            return

        # Get the file part (prefer 'file' over 'attachment')
        file_part = parts.get('file') or parts.get('attachment')
        if not file_part:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing file field'
            })
            return

        filename = file_part.get('filename', '')
        content_bytes = file_part.get('content', b'')

        if not filename or not content_bytes:
            self.send_json_response(400, {
                'ok': False,
                'error': 'Missing file field'
            })
            return

        # Determine format and parse
        try:
            if filename.endswith('.csv'):
                charset = None
                columns, rows = parse_csv_content(content_bytes, charset)
            elif filename.endswith(('.xls', '.xlsx')):
                columns, rows = parse_excel_content(content_bytes, filename)
            else:
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Unsupported format'
                })
                return
        except ValueError as e:
            self.send_json_response(400, {
                'ok': False,
                'error': str(e)
            })
            return

        # Generate deterministic ID based on file content bytes
        dataset_id = generate_dataset_id(content_bytes.decode('utf-8', errors='replace'))

        # Store dataset
        datasets[dataset_id] = {
            'columns': columns,
            'rows': rows
        }

        self.send_json_response(200, {
            'ok': True,
            'endpoint': f'/datasets/{dataset_id}'
        })

    def parse_multipart(self, body: bytes, boundary: str) -> dict:
        """Parse multipart form data."""
        parts = {}

        # Create boundary markers
        boundary_bytes = f'--{boundary}'.encode('utf-8')
        boundary_end = f'--{boundary}--'.encode('utf-8')

        # Split by boundaries
        sections = body.split(boundary_bytes)

        for section in sections:
            if not section or section == body:
                continue

            # Strip leading and trailing newlines
            section = section.strip()
            if section.endswith(boundary_end[len(boundary_bytes):]):
                section = section[:-len(boundary_end) + len(boundary_bytes)].strip()

            # Parse headers and content
            header_end = section.find(b'\r\n\r\n')
            if header_end == -1:
                continue

            headers_section = section[:header_end].decode('utf-8', errors='replace')
            content = section[header_end + 4:]  # Skip \r\n\r\n

            # Parse headers to find field name and filename
            headers = {}
            for line in headers_section.split('\r\n'):
                if ':' in line:
                    key, value = line.split(':', 1)
                    headers[key.strip().lower()] = value.strip()

            # Extract field name from Content-Disposition
            content_disposition = headers.get('content-disposition', '')

            field_name = None
            filename = None

            if 'name=' in content_disposition:
                import re as re_module
                match = re_module.search(r'name="([^"]*)"', content_disposition)
                if match:
                    field_name = match.group(1)

            if 'filename=' in content_disposition:
                import re as re_module
                match = re_module.search(r'filename="([^"]*)"', content_disposition)
                if match:
                    filename = match.group(1)

            if field_name:
                parts[field_name] = {
                    'filename': filename,
                    'content': content
                }

        return parts

    def handle_export(self, dataset_id: str, query_params: dict):
        """Handle GET /datasets/<id>/export endpoint."""
        if dataset_id not in datasets:
            self.send_json_response(404, {
                'ok': False,
                'error': 'Dataset not found'
            })
            return

        dataset = datasets[dataset_id]
        columns = dataset['columns']
        rows = dataset['rows']

        # Get control parameters (same as dataset endpoint but ignore pagination)
        _sort = query_params.get('_sort', [None])[0]
        _sort_desc = query_params.get('_sort_desc', [None])[0]

        # Determine sort column
        if _sort_desc:
            sort_col = _sort_desc
            reverse = True
        elif _sort:
            sort_col = _sort
            reverse = False
        else:
            sort_col = None
            reverse = False

        # Validate sort column exists
        if sort_col:
            if sort_col not in columns:
                self.send_json_response(400, {
                    'ok': False,
                    'error': f"Unknown column: {sort_col}"
                })
                return

        # Build filter list from query params (simplified - use same logic as handle_dataset)
        filters = self.build_filters(query_params)

        # Apply filters
        filtered_rows = self.apply_filters(rows, columns, filters)

        # Sorting applied BEFORE pagination (but export returns all data, so pagination doesn't apply)
        if sort_col:
            col_index = columns.index(sort_col)
            def sort_key(item):
                val = item[columns.index(sort_col)]
                t = type(val)
                if t is int or t is float:
                    return (0, val)
                elif val == '':
                    return (2, '')
                else:
                    return (1, str(val))
            filtered_rows = sorted(filtered_rows, key=sort_key, reverse=reverse)

        # Generate CSV
        output = io.StringIO()
        writer = csv.writer(output)

        # Write header in source column order
        writer.writerow(columns)

        # Write all rows
        for row in filtered_rows:
            writer.writerow([str(cell) if cell is not None else '' for cell in row])

        csv_content = output.getvalue().encode('utf-8')

        # Send CSV response
        self.send_response(200)
        self.send_header('Content-Type', 'text/csv')
        self.send_header('Content-Disposition', f'attachment; filename="{dataset_id}.csv"')
        self.send_header('Content-Length', str(len(csv_content)))
        self.send_cors_headers()
        self.end_headers()
        self.wfile.write(csv_content)

    def handle_dataset(self, dataset_id: str):
        """Handle /datasets/<id> endpoint."""
        if dataset_id not in datasets:
            self.send_json_response(404, {
                'ok': False,
                'error': 'Dataset not found'
            })
            return

        dataset = datasets[dataset_id]
        parsed_path = urlparse(self.path)
        query_params = parse_qs(parsed_path.query)
        start_time = time.time()

        # Validate and parse control parameters
        error_response = self.validate_control_params(query_params)
        if error_response:
            self.send_json_response(400, error_response)
            return

        # Extract parameter values (parse_qs returns lists)
        _size = int(query_params.get('_size', ['100'])[0])
        _offset = int(query_params.get('_offset', ['0'])[0])
        _shape = query_params.get('_shape', ['lists'])[0]
        _sort = query_params.get('_sort', [None])[0]
        _sort_desc = query_params.get('_sort_desc', [None])[0]
        _rowid = query_params.get('_rowid', [None])[0]
        _total = query_params.get('_total', [None])[0]

        columns = dataset['columns']
        rows = dataset['rows']

        # Determine sort column (if both _sort and _sort_desc are present, _sort_desc wins)
        if _sort_desc:
            sort_col = _sort_desc
            reverse = True
        elif _sort:
            sort_col = _sort
            reverse = False
        else:
            sort_col = None
            reverse = False

        # Validate sort column exists
        if sort_col:
            if sort_col not in columns:
                self.send_json_response(400, {
                    'ok': False,
                    'error': f"Unknown column: {sort_col}"
                })
                return
            # Validate _sort and _sort_desc are not empty strings
            if (_sort and _sort.strip() == '') or (_sort_desc and _sort_desc.strip() == ''):
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Empty column name for sorting'
                })
                return

        # Parse and validate filters
        filter_errors = self.validate_and_parse_filters(query_params, columns)
        if filter_errors:
            self.send_json_response(400, filter_errors)
            return

        # Validate duplicate filter keys (same key with multiple values)
        duplicate_filter_error = self.validate_filter_keys(query_params)
        if duplicate_filter_error:
            self.send_json_response(400, duplicate_filter_error)
            return

        # Build filter list from query params
        filters = self.build_filters(query_params)

        # Apply filters to rows
        filtered_rows = self.apply_filters(rows, columns, filters)
        filtered_count = len(filtered_rows)

        # Create a copy with original indices for rowid tracking
        # tuples: (original_index, row_data)
        indexed_rows = list(enumerate(filtered_rows))

        # Sorting - applied BEFORE pagination
        if sort_col:
            col_index = columns.index(sort_col)
            # Sort with safe type handling to handle mixed types
            def sort_key(item):
                val = item[1][col_index]
                t = type(val)
                # Use a tuple (type_priority, value) for cross-type comparison
                if t is int or t is float:
                    return (0, val)
                elif val == '':
                    # Empty strings sort last
                    return (2, '')
                else:
                    # String values sort in middle
                    return (1, str(val))
            # Stable sort using index as secondary key
            indexed_rows = sorted(indexed_rows, key=lambda x: (sort_key(x), x[0]), reverse=reverse)

        total = len(indexed_rows)

        # Apply pagination - only on the data, not the indices
        paginated_indexed = indexed_rows[_offset:_offset + _size]

        # Handle visibility toggles
        include_total = _total != 'hide'
        hide_rowid = _rowid == 'hide'

        # Apply shape transformation (rowid handling is inside this block)
        if _shape == 'objects':
            rows_to_return = []
            for orig_idx, row in paginated_indexed:
                row_obj = {}
                if not hide_rowid:  # Include rowid unless explicitly hidden
                    row_obj['rowid'] = orig_idx + 1  # 1-based source-file row number
                for j, col in enumerate(columns):
                    row_obj[col] = row[j]
                rows_to_return.append(row_obj)
        else:
            rows_to_return = [row for _, row in paginated_indexed]

        # Build response
        response = {
            'ok': True,
            'columns': columns,
            'rows': rows_to_return,
            'query_ms': round((time.time() - start_time) * 1000, 1)
        }

        if include_total:
            response['total'] = total

        self.send_json_response(200, response)

    def validate_and_parse_filters(self, query_params: dict, columns: list) -> dict | None:
        """Validate filter parameters and return error response if invalid, None if valid."""
        valid_comparators = {'exact', 'contains', 'less', 'greater'}

        for key, values in query_params.items():
            if key.startswith('_') or '__' not in key:
                continue

            # Key should have exactly one __ (column__comparator format)
            if key.count('__') != 1:
                return {
                    'ok': False,
                    'error': f"Invalid filter format: {key}"
                }

            column, comparator = key.split('__', 1)

            # Validate comparator
            if comparator not in valid_comparators:
                return {
                    'ok': False,
                    'error': f"Invalid comparator: {comparator}"
                }

            # Validate column exists
            if column not in columns:
                return {
                    'ok': False,
                    'error': f"Unknown column: {column}"
                }

            # Validate value exists (parse_qs returns lists)
            if not values or len(values) == 0:
                return {
                    'ok': False,
                    'error': f"Missing value for filter: {key}"
                }

            value_str = values[0]

            # For numeric comparators, validate that the filter value is numeric
            if comparator in ('less', 'greater'):
                try:
                    float(value_str)
                except ValueError:
                    return {
                        'ok': False,
                        'error': f"Comparator target not numeric: {key}"
                    }

        return None

    def validate_filter_keys(self, query_params: dict) -> dict | None:
        """Validate that filter keys don't have multiple values (duplicate keys)."""
        for key, values in query_params.items():
            if key.startswith('_') or '__' not in key:
                continue
            # parse_qs returns lists, so a single key with multiple values is a duplicate
            if len(values) > 1:
                return {
                    'ok': False,
                    'error': f"Duplicate filter key: {key}"
                }
        return None

    def build_filters(self, query_params: dict) -> list:
        """Build a list of filter tuples from query parameters."""
        filters = []
        valid_comparators = {'exact', 'contains', 'less', 'greater'}

        for key, values in query_params.items():
            if key.startswith('_') or '__' not in key:
                continue

            column, comparator = key.split('__', 1)
            value_str = values[0]

            # Convert filter value to appropriate type for numeric comparators
            filter_value = value_str
            if comparator in ('less', 'greater'):
                filter_value = float(value_str)

            filters.append({
                'column': column,
                'comparator': comparator,
                'value': filter_value
            })

        return filters

    def apply_filters(self, rows: list, columns: list, filters: list) -> list:
        """Apply all filters to rows and return filtered rows."""
        if not filters:
            return rows[:]

        filtered = []
        for row in rows:
            matches_all = True
            for f in filters:
                if not self._row_matches_filter(row, columns, f):
                    matches_all = False
                    break
            if matches_all:
                filtered.append(row)

        return filtered

    def _row_matches_filter(self, row: list, columns: list, filter_spec: dict) -> bool:
        """Check if a single row matches a filter specification."""
        col_index = columns.index(filter_spec['column'])
        row_value = row[col_index]
        comparator = filter_spec['comparator']
        filter_value = filter_spec['value']

        if comparator == 'exact':
            return str(row_value) == str(filter_value)

        elif comparator == 'contains':
            return str(filter_value) in str(row_value)

        elif comparator == 'less':
            # Non-numeric stored values are not matched
            if not isinstance(row_value, (int, float)):
                return False
            return row_value < filter_value

        elif comparator == 'greater':
            # Non-numeric stored values are not matched
            if not isinstance(row_value, (int, float)):
                return False
            return row_value > filter_value

        return False

    def validate_control_params(self, query_params: dict) -> dict | None:
        """Validate control parameters and return error response if invalid, None if valid."""
        # Check for repeated parameters
        repeated_params = []
        for param in ['_size', '_offset', '_shape', '_sort', '_sort_desc', '_rowid', '_total']:
            if param in query_params and len(query_params[param]) > 1:
                repeated_params.append(param)
        if repeated_params:
            return {
                'ok': False,
                'error': f"Repeated parameter: {', '.join(repeated_params)}"
            }

        # Validate _size
        if '_size' in query_params:
            try:
                size = int(query_params['_size'][0])
                if size <= 0:
                    return {'ok': False, 'error': '_size must be a positive integer'}
            except ValueError:
                return {'ok': False, 'error': '_size must be a positive integer'}

        # Validate _offset
        if '_offset' in query_params:
            try:
                offset = int(query_params['_offset'][0])
                if offset < 0:
                    return {'ok': False, 'error': '_offset must be a non-negative integer'}
            except ValueError:
                return {'ok': False, 'error': '_offset must be a non-negative integer'}

        # Validate _shape
        if '_shape' in query_params:
            shape = query_params['_shape'][0]
            if shape not in ['lists', 'objects']:
                return {'ok': False, 'error': '_shape must be lists or objects'}

        # Validate _rowid
        if '_rowid' in query_params:
            rowid = query_params['_rowid'][0]
            if rowid != 'hide':
                return {'ok': False, 'error': '_rowid must be hide'}

        # Validate _total
        if '_total' in query_params:
            total = query_params['_total'][0]
            if total != 'hide':
                return {'ok': False, 'error': '_total must be hide'}

        # Validate _query_timeout
        if '_query_timeout' in query_params:
            timeout = query_params['_query_timeout'][0]
            if not timeout.isdigit():
                return {'ok': False, 'error': '_query_timeout must be a positive integer'}
            if int(timeout) <= 0:
                return {'ok': False, 'error': '_query_timeout must be a positive integer'}
            # Even if valid, we reject it as query timeout means the request took too long
            return {'ok': False, 'error': 'Query timeout'}

        return None

    def _check_origin_allowlist(self) -> bool:
        """Check if the request's Referer is allowed by the allowlist.

        Returns:
            True if allowlist is not configured or referer is allowed.
            False if allowlist is configured and referer is not allowed.
        """
        # If no allowlist configured, all requests pass
        if not config.origin_allowlist:
            return True

        # Check for Referer header
        referer = self.headers.get('Referer') or self.headers.get('Referer')
        if not referer:
            return False

        # Parse hostname from referer
        try:
            parsed = urlparse(referer)
            hostname = parsed.hostname
            if not hostname:
                return False
        except Exception:
            return False

        # Check against allowed suffixes (case-insensitive with domain boundary)
        hostname_lower = hostname.lower()
        for allowed_suffix in config.origin_allowlist:
            suffix_lower = allowed_suffix.lower()
            # Check for domain boundary: hostname must end with suffix
            # and the character before suffix must be '.' or be at start
            if hostname_lower == suffix_lower:
                return True
            if hostname_lower.endswith('.' + suffix_lower):
                return True

        return False

    def _enforce_size_limit(self, content_length: int) -> bool:
        """Check if content size is within limit.

        Returns:
            True if within limit or no limit set.
            False if exceeds limit.
        """
        if config.max_source_size is None:
            return True
        return content_length <= config.max_source_size

    def _is_upload_or_convert(self) -> bool:
        """Check if this is an upload or convert endpoint."""
        return self.path in ['/convert', '/upload']

    def do_OPTIONS(self):
        ""Handle CORS preflight requests."""
        # Check origin allowlist for preflight
        if not self._check_origin_allowlist():
            referer = self.headers.get('Referer', '')
            if not referer:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Missing Referer header'
                })
            else:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Referer not allowed'
                })
            return

        self.send_response(200)
        self.send_cors_headers()
        self.end_headers()

    def do_GET(self):
        ""Handle GET requests."""
        # Check origin allowlist for GET requests
        if not self._check_origin_allowlist():
            referer = self.headers.get('Referer', '')
            if not referer:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Missing Referer header'
                })
            else:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Referer not allowed'
                })
            return

        parsed_path = urlparse(self.path)
        path = parsed_path.path
        query_params = parse_qs(parsed_path.query)

        # Debug logging
        sys.stderr.write(f"DEBUG: path={path}, query={parsed_path.query}, params={query_params}\n")

        try:
            if path == '/convert':
                self.handle_convert(query_params)
            elif path.endswith('/export') and '/datasets/' in path:
                # Handle /datasets/<id>/export
                dataset_id = path.split('/')[2]  # datasets/<id>/export
                self.handle_export(dataset_id, query_params)
            elif path.startswith('/datasets/'):
                dataset_id = path.split('/')[-1]
                self.handle_dataset(dataset_id)
            else:
                self.send_json_response(404, {
                    'ok': False,
                    'error': 'Not found'
                })
        except Exception as e:
            self.send_json_response(500, {
                'ok': False,
                'error': str(e)
            })

    def do_POST(self):
        ""Handle POST requests."""
        # Check origin allowlist for POST requests
        if not self._check_origin_allowlist():
            referer = self.headers.get('Referer', '')
            if not referer:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Missing Referer header'
                })
            else:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Referer not allowed'
                })
            return

        parsed_path = urlparse(self.path)
        path = parsed_path.path

        # Check content size for /convert and /upload
        if path in ['/convert', '/upload']:
            content_length = int(self.headers.get('Content-Length', 0))
            if not self._enforce_size_limit(content_length):
                self.send_json_response(400, {
                    'ok': False,
                    'error': f'File size exceeds maximum allowed size of {config.max_source_size} bytes'
                })
                return

        try:
            if path == '/upload':
                self.handle_upload()
            elif path == '/convert':
                self.handle_convert_post()
            else:
                self.send_json_response(404, {
                    'ok': False,
                    'error': 'Not found'
                })
        except Exception as e:
            self.send_json_response(500, {
                'ok': False,
                'error': str(e)
            })
    parser = argparse.ArgumentParser(description='Datagate - CSV conversion server')
    subparsers = parser.add_subparsers(dest='command', help='Command to run')

    start_parser = subparsers.add_parser('start', help='Start the server')
    start_parser.add_argument('--port', type=int, default=8001, help='Port to listen on (default: 8001)')
    start_parser.add_argument('--address', type=str, default='127.0.0.1', help='Address to bind to (default: 127.0.0.1)')

    args = parser.parse_args()

    if args.command != 'start':
        parser.print_help()
        sys.exit(1)

    server = HTTPServer((args.address, args.port), DatagateHandler)
    print(f'Datagate server starting on {args.address}:{args.port}')
    print('Press Ctrl+C to stop')

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print('\nShutting down server...')
        server.shutdown()


