        raise ValueError(f"Source unreachable: {str(e)}")
    except Exception as e:
        raise ValueError(f"Failed to fetch source: {str(e)}")

    # Check size limit for remote content if configured
    if config.max_source_size is not None:
        if len(content) > config.max_source_size:
            raise ValueError(f"Source size exceeds maximum allowed size of {config.max_source_size} bytes")

    return parse_csv_content(content, charset)

