    def parse_multipart(self, body: bytes, boundary: str) -> dict:
        """Parse multipart form data."""
        parts = {}

        # Create boundary markers
        boundary_bytes = f'--{boundary}'.encode('utf-8')
        boundary_end = f'--{boundary}--'.encode('utf-8')

        # Split by boundaries
        sections = body.split(boundary_bytes)

        for section in sections:
            if not section or section == body:
                continue

            # Strip leading and trailing newlines
            section = section.strip()
            if section.endswith(boundary_end[len(boundary_bytes):]):
                section = section[:-len(boundary_end) + len(boundary_bytes)].strip()

            # Parse headers and content
            header_end = section.find(b'\r\n\r\n')
            if header_end == -1:
                continue

            headers_section = section[:header_end].decode('utf-8', errors='replace')
            content = section[header_end + 4:]  # Skip \r\n\r\n

            # Parse headers to find field name and filename
            headers = {}
            for line in headers_section.split('\r\n'):
                if ':' in line:
                    key, value = line.split(':', 1)
                    headers[key.strip().lower()] = value.strip()

            # Extract field name from Content-Disposition
            content_disposition = headers.get('content-disposition', '')

            field_name = None
            filename = None

            if 'name=' in content_disposition:
                import re as re_module
                match = re_module.search(r'name="([^"]*)"', content_disposition)
                if match:
                    field_name = match.group(1)

            if 'filename=' in content_disposition:
                import re as re_module
                match = re_module.search(r'filename="([^"]*)"', content_disposition)
                if match:
                    filename = match.group(1)

            if field_name:
                parts[field_name] = {
                    'filename': filename,
                    'content': content
                }

        return parts

    def handle_export(self, dataset_id: str, query_params: dict):
        """Handle GET /datasets/<id>/export endpoint."""
        if dataset_id not in datasets:
            self.send_json_response(404, {
                'ok': False,
                'error': 'Dataset not found'
            })
            return

        dataset = datasets[dataset_id]
        columns = dataset['columns']
        rows = dataset['rows']

        # Get control parameters (same as dataset endpoint but ignore pagination)
        _sort = query_params.get('_sort', [None])[0]
        _sort_desc = query_params.get('_sort_desc', [None])[0]

        # Determine sort column
        if _sort_desc:
            sort_col = _sort_desc
            reverse = True
        elif _sort:
            sort_col = _sort
            reverse = False
        else:
            sort_col = None
            reverse = False

        # Validate sort column exists
        if sort_col:
            if sort_col not in columns:
                self.send_json_response(400, {
                    'ok': False,
                    'error': f"Unknown column: {sort_col}"
                })
                return

        # Build filter list from query params (simplified - use same logic as handle_dataset)
        filters = self.build_filters(query_params)

        # Apply filters
        filtered_rows = self.apply_filters(rows, columns, filters)

        # Sorting applied BEFORE pagination (but export returns all data, so pagination doesn't apply)
        if sort_col:
            col_index = columns.index(sort_col)
            def sort_key(item):
                val = item[columns.index(sort_col)]
                t = type(val)
                if t is int or t is float:
                    return (0, val)
                elif val == '':
                    return (2, '')
                else:
                    return (1, str(val))
            filtered_rows = sorted(filtered_rows, key=sort_key, reverse=reverse)

        # Generate CSV
        output = io.StringIO()
        writer = csv.writer(output)

        # Write header in source column order
        writer.writerow(columns)

        # Write all rows
        for row in filtered_rows:
            writer.writerow([str(cell) if cell is not None else '' for cell in row])

        csv_content = output.getvalue().encode('utf-8')

        # Send CSV response
        self.send_response(200)
        self.send_header('Content-Type', 'text/csv')
        self.send_header('Content-Disposition', f'attachment; filename="{dataset_id}.csv"')
        self.send_header('Content-Length', str(len(csv_content)))
        self.send_cors_headers()
        self.end_headers()
        self.wfile.write(csv_content)

    def handle_dataset(self, dataset_id: str):
        """Handle /datasets/<id> endpoint."""
        if dataset_id not in datasets:
            self.send_json_response(404, {
                'ok': False,
                'error': 'Dataset not found'
            })
            return

        dataset = datasets[dataset_id]
        parsed_path = urlparse(self.path)
        query_params = parse_qs(parsed_path.query)
        start_time = time.time()

        # Validate and parse control parameters
        error_response = self.validate_control_params(query_params)
        if error_response:
            self.send_json_response(400, error_response)
            return

        # Extract parameter values (parse_qs returns lists)
        _size = int(query_params.get('_size', ['100'])[0])
        _offset = int(query_params.get('_offset', ['0'])[0])
        _shape = query_params.get('_shape', ['lists'])[0]
        _sort = query_params.get('_sort', [None])[0]
        _sort_desc = query_params.get('_sort_desc', [None])[0]
        _rowid = query_params.get('_rowid', [None])[0]
        _total = query_params.get('_total', [None])[0]

        columns = dataset['columns']
        rows = dataset['rows']

        # Determine sort column (if both _sort and _sort_desc are present, _sort_desc wins)
        if _sort_desc:
            sort_col = _sort_desc
            reverse = True
        elif _sort:
            sort_col = _sort
            reverse = False
        else:
            sort_col = None
            reverse = False

        # Validate sort column exists
        if sort_col:
            if sort_col not in columns:
                self.send_json_response(400, {
                    'ok': False,
                    'error': f"Unknown column: {sort_col}"
                })
                return
            # Validate _sort and _sort_desc are not empty strings
            if (_sort and _sort.strip() == '') or (_sort_desc and _sort_desc.strip() == ''):
                self.send_json_response(400, {
                    'ok': False,
                    'error': 'Empty column name for sorting'
                })
                return

        # Parse and validate filters
        filter_errors = self.validate_and_parse_filters(query_params, columns)
        if filter_errors:
            self.send_json_response(400, filter_errors)
            return

        # Validate duplicate filter keys (same key with multiple values)
        duplicate_filter_error = self.validate_filter_keys(query_params)
        if duplicate_filter_error:
            self.send_json_response(400, duplicate_filter_error)
            return

        # Build filter list from query params
        filters = self.build_filters(query_params)

        # Apply filters to rows
        filtered_rows = self.apply_filters(rows, columns, filters)
        filtered_count = len(filtered_rows)

        # Create a copy with original indices for rowid tracking
        # tuples: (original_index, row_data)
        indexed_rows = list(enumerate(filtered_rows))

        # Sorting - applied BEFORE pagination
        if sort_col:
            col_index = columns.index(sort_col)
            # Sort with safe type handling to handle mixed types
            def sort_key(item):
                val = item[1][col_index]
                t = type(val)
                # Use a tuple (type_priority, value) for cross-type comparison
                if t is int or t is float:
                    return (0, val)
                elif val == '':
                    # Empty strings sort last
                    return (2, '')
                else:
                    # String values sort in middle
                    return (1, str(val))
            # Stable sort using index as secondary key
            indexed_rows = sorted(indexed_rows, key=lambda x: (sort_key(x), x[0]), reverse=reverse)

        total = len(indexed_rows)

        # Apply pagination - only on the data, not the indices
        paginated_indexed = indexed_rows[_offset:_offset + _size]

        # Handle visibility toggles
        include_total = _total != 'hide'
        hide_rowid = _rowid == 'hide'

        # Apply shape transformation (rowid handling is inside this block)
        if _shape == 'objects':
            rows_to_return = []
            for orig_idx, row in paginated_indexed:
                row_obj = {}
                if not hide_rowid:  # Include rowid unless explicitly hidden
                    row_obj['rowid'] = orig_idx + 1  # 1-based source-file row number
                for j, col in enumerate(columns):
                    row_obj[col] = row[j]
                rows_to_return.append(row_obj)
        else:
            rows_to_return = [row for _, row in paginated_indexed]

        # Build response
        response = {
            'ok': True,
            'columns': columns,
            'rows': rows_to_return,
            'query_ms': round((time.time() - start_time) * 1000, 1)
        }

        if include_total:
            response['total'] = total

        self.send_json_response(200, response)

    def validate_and_parse_filters(self, query_params: dict, columns: list) -> dict | None:
        """Validate filter parameters and return error response if invalid, None if valid."""
        valid_comparators = {'exact', 'contains', 'less', 'greater'}

        for key, values in query_params.items():
            if key.startswith('_') or '__' not in key:
                continue

            # Key should have exactly one __ (column__comparator format)
            if key.count('__') != 1:
                return {
                    'ok': False,
                    'error': f"Invalid filter format: {key}"
                }

            column, comparator = key.split('__', 1)

            # Validate comparator
            if comparator not in valid_comparators:
                return {
                    'ok': False,
                    'error': f"Invalid comparator: {comparator}"
                }

            # Validate column exists
            if column not in columns:
                return {
                    'ok': False,
                    'error': f"Unknown column: {column}"
                }

            # Validate value exists (parse_qs returns lists)
            if not values or len(values) == 0:
                return {
                    'ok': False,
                    'error': f"Missing value for filter: {key}"
                }

            value_str = values[0]

            # For numeric comparators, validate that the filter value is numeric
            if comparator in ('less', 'greater'):
                try:
                    float(value_str)
                except ValueError:
                    return {
                        'ok': False,
                        'error': f"Comparator target not numeric: {key}"
                    }

        return None

    def validate_filter_keys(self, query_params: dict) -> dict | None:
        """Validate that filter keys don't have multiple values (duplicate keys)."""
        for key, values in query_params.items():
            if key.startswith('_') or '__' not in key:
                continue
            # parse_qs returns lists, so a single key with multiple values is a duplicate
            if len(values) > 1:
                return {
                    'ok': False,
                    'error': f"Duplicate filter key: {key}"
                }
        return None

    def build_filters(self, query_params: dict) -> list:
        """Build a list of filter tuples from query parameters."""
        filters = []
        valid_comparators = {'exact', 'contains', 'less', 'greater'}

        for key, values in query_params.items():
            if key.startswith('_') or '__' not in key:
                continue

            column, comparator = key.split('__', 1)
            value_str = values[0]

            # Convert filter value to appropriate type for numeric comparators
            filter_value = value_str
            if comparator in ('less', 'greater'):
                filter_value = float(value_str)

            filters.append({
                'column': column,
                'comparator': comparator,
                'value': filter_value
            })

        return filters

    def apply_filters(self, rows: list, columns: list, filters: list) -> list:
        """Apply all filters to rows and return filtered rows."""
        if not filters:
            return rows[:]

        filtered = []
        for row in rows:
            matches_all = True
            for f in filters:
                if not self._row_matches_filter(row, columns, f):
                    matches_all = False
                    break
            if matches_all:
                filtered.append(row)

        return filtered

    def _row_matches_filter(self, row: list, columns: list, filter_spec: dict) -> bool:
        """Check if a single row matches a filter specification."""
        col_index = columns.index(filter_spec['column'])
        row_value = row[col_index]
        comparator = filter_spec['comparator']
        filter_value = filter_spec['value']

        if comparator == 'exact':
            return str(row_value) == str(filter_value)

        elif comparator == 'contains':
            return str(filter_value) in str(row_value)

        elif comparator == 'less':
            # Non-numeric stored values are not matched
            if not isinstance(row_value, (int, float)):
                return False
            return row_value < filter_value

        elif comparator == 'greater':
            # Non-numeric stored values are not matched
            if not isinstance(row_value, (int, float)):
                return False
            return row_value > filter_value

        return False

    def validate_control_params(self, query_params: dict) -> dict | None:
        """Validate control parameters and return error response if invalid, None if valid."""
        # Check for repeated parameters
        repeated_params = []
        for param in ['_size', '_offset', '_shape', '_sort', '_sort_desc', '_rowid', '_total']:
            if param in query_params and len(query_params[param]) > 1:
                repeated_params.append(param)
        if repeated_params:
            return {
                'ok': False,
                'error': f"Repeated parameter: {', '.join(repeated_params)}"
            }

        # Validate _size
        if '_size' in query_params:
            try:
                size = int(query_params['_size'][0])
                if size <= 0:
                    return {'ok': False, 'error': '_size must be a positive integer'}
            except ValueError:
                return {'ok': False, 'error': '_size must be a positive integer'}

        # Validate _offset
        if '_offset' in query_params:
            try:
                offset = int(query_params['_offset'][0])
                if offset < 0:
                    return {'ok': False, 'error': '_offset must be a non-negative integer'}
            except ValueError:
                return {'ok': False, 'error': '_offset must be a non-negative integer'}

        # Validate _shape
        if '_shape' in query_params:
            shape = query_params['_shape'][0]
            if shape not in ['lists', 'objects']:
                return {'ok': False, 'error': '_shape must be lists or objects'}

        # Validate _rowid
        if '_rowid' in query_params:
            rowid = query_params['_rowid'][0]
            if rowid != 'hide':
                return {'ok': False, 'error': '_rowid must be hide'}

        # Validate _total
        if '_total' in query_params:
            total = query_params['_total'][0]
            if total != 'hide':
                return {'ok': False, 'error': '_total must be hide'}

        # Validate _query_timeout
        if '_query_timeout' in query_params:
            timeout = query_params['_query_timeout'][0]
            if not timeout.isdigit():
                return {'ok': False, 'error': '_query_timeout must be a positive integer'}
            if int(timeout) <= 0:
                return {'ok': False, 'error': '_query_timeout must be a positive integer'}
            # Even if valid, we reject it as query timeout means the request took too long
            return {'ok': False, 'error': 'Query timeout'}

        return None

    def _check_origin_allowlist(self) -> bool:
        """Check if the request's Referer is allowed by the allowlist.

        Returns:
            True if allowlist is not configured or referer is allowed.
            False if allowlist is configured and referer is not allowed.
        """
        # If no allowlist configured, all requests pass
        if not config.origin_allowlist:
            return True

        # Check for Referer header
        referer = self.headers.get('Referer') or self.headers.get('Referer')
        if not referer:
            return False

        # Parse hostname from referer
        try:
            parsed = urlparse(referer)
            hostname = parsed.hostname
            if not hostname:
                return False
        except Exception:
            return False

        # Check against allowed suffixes (case-insensitive with domain boundary)
        hostname_lower = hostname.lower()
        for allowed_suffix in config.origin_allowlist:
            suffix_lower = allowed_suffix.lower()
            # Check for domain boundary: hostname must end with suffix
            # and the character before suffix must be '.' or be at start
            if hostname_lower == suffix_lower:
                return True
            if hostname_lower.endswith('.' + suffix_lower):
                return True

        return False

    def _enforce_size_limit(self, content_length: int) -> bool:
        """Check if content size is within limit.

        Returns:
            True if within limit or no limit set.
            False if exceeds limit.
        """
        if config.max_source_size is None:
            return True
        return content_length <= config.max_source_size

    def _is_upload_or_convert(self) -> bool:
        """Check if this is an upload or convert endpoint."""
        return self.path in ['/convert', '/upload']

    def do_OPTIONS(self):
        ""Handle CORS preflight requests."""
        # Check origin allowlist for preflight
        if not self._check_origin_allowlist():
            referer = self.headers.get('Referer', '')
            if not referer:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Missing Referer header'
                })
            else:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Referer not allowed'
                })
            return

        self.send_response(200)
        self.send_cors_headers()
        self.end_headers()

    def do_GET(self):
        ""Handle GET requests."""
        # Check origin allowlist for GET requests
        if not self._check_origin_allowlist():
            referer = self.headers.get('Referer', '')
            if not referer:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Missing Referer header'
                })
            else:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Referer not allowed'
                })
            return

        parsed_path = urlparse(self.path)
        path = parsed_path.path
        query_params = parse_qs(parsed_path.query)

        # Debug logging
        sys.stderr.write(f"DEBUG: path={path}, query={parsed_path.query}, params={query_params}\n")

        try:
            if path == '/convert':
                self.handle_convert(query_params)
            elif path.endswith('/export') and '/datasets/' in path:
                # Handle /datasets/<id>/export
                dataset_id = path.split('/')[2]  # datasets/<id>/export
                self.handle_export(dataset_id, query_params)
            elif path.startswith('/datasets/'):
                dataset_id = path.split('/')[-1]
                self.handle_dataset(dataset_id)
            else:
                self.send_json_response(404, {
                    'ok': False,
                    'error': 'Not found'
                })
        except Exception as e:
            self.send_json_response(500, {
                'ok': False,
                'error': str(e)
            })

    def do_POST(self):
        ""Handle POST requests."""
        # Check origin allowlist for POST requests
        if not self._check_origin_allowlist():
            referer = self.headers.get('Referer', '')
            if not referer:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Missing Referer header'
                })
            else:
                self.send_json_response(403, {
                    'ok': False,
                    'error': 'Referer not allowed'
                })
            return

        parsed_path = urlparse(self.path)
        path = parsed_path.path

        # Check content size for /convert and /upload
        if path in ['/convert', '/upload']:
            content_length = int(self.headers.get('Content-Length', 0))
            if not self._enforce_size_limit(content_length):
                self.send_json_response(400, {
                    'ok': False,
                    'error': f'File size exceeds maximum allowed size of {config.max_source_size} bytes'
                })
                return

        try:
            if path == '/upload':
                self.handle_upload()
            elif path == '/convert':
                self.handle_convert_post()
            else:
                self.send_json_response(404, {
                    'ok': False,
                    'error': 'Not found'
                })
        except Exception as e:
            self.send_json_response(500, {
                'ok': False,
                'error': str(e)
            })


